li x5, 1                                          # Load desired vl value
vsetvli x0, x5, e16, m1, tu, mu
la x4, vd_random_base_089                         # Load address of desired value
vle32.v v22, (x4)                                 # Load desired value from memory into v22
la x27, custom_flag_wide_of_sew16                 # Load address of desired value
vle32.v v14, (x27)                                # Load desired value from memory into v14
la x30, custom_flag_one_sew16                     # Load address of desired value
vle16.v v0, (x30)                                 # Load desired value from memory into v0
Vf16_vfwadd_wv_cg_cp_custom_vfp_flags_nv_nx_duplicate_5:
vfwadd.wv v22, v14, v0
csrr x2, fcsr                                     # save fcsr into x2 for signature
RVTEST_SIGUPD(x26, x5, x4, x2, Vf16_vfwadd_wv_cg_cp_custom_vfp_flags_nv_nx_duplicate_5, test_605_str)# store x2 in signature
vsetivli x0, 1, e32, m1, tu, mu                   # set SEW=32, LMUL=1, VL=1 before signature check
# RVTEST_SIGUPD_V(_CMP, _SIG_PTR, _LINK_REG, _TEMP_REG, _VTMP, _MTMP, _SEW, _OFFSET, _VREG, _INST_PTR, _STR_PTR)
RVTEST_SIGUPD_V(vmsne.vv, x26, x5, x4, v6, v8, 32, 8, v22, Vf16_vfwadd_wv_cg_cp_custom_vfp_flags_nv_nx_duplicate_5, test_605_str)# Check if v22 contains the expected result. x26 is the signature ptr, x5 is the link ptr, x4 is a temp reg.
#endif

